function injectMojibakeCleaner(html){
  var cleaner = mojibakeCleanerScript();
  if(html.indexOf('mojibakeCleanerScript')>=0) return html;
  if(/<\/body>/i.test(html)) return html.replace(/<\/body>/i, cleaner + '<\/body>');
  return html + cleaner;
}
function loadEmbeddedHtml(frameId, payload){
  var frame = document.getElementById(frameId);
  if(!frame || frame.dataset.loaded) return;
  var bin = atob(payload);
  var bytes = new Uint8Array(bin.length);
  for(var i=0;i<bin.length;i++) bytes[i] = bin.charCodeAt(i);
  frame.srcdoc = injectMojibakeCleaner(new TextDecoder("utf-8").decode(bytes));
  frame.dataset.loaded = "1";
}
function loadVerbTenses(){loadEmbeddedHtml("verbTensesFrame", VERBTENSESEMBED)}

