/* Sub-category classifications. Used to pick natural example sentences.
   F=frequency, T=time, M=manner, D=degree(intensity), P=probability/certainty,
   V=viewpoint(point of view, "-ly" comment), Z=focus(only/just/especially),
   L=place, C=conjunctive(connector), CM=comment(luckily,frankly...), MA=evaluator(wisely) */
var ADV_KIND={};
["always","usually","often","frequently","regularly","generally","normally","typically",
 "occasionally","sometimes","rarely","seldom","hardly","barely","scarcely","never","ever",
 "constantly","continuously","perpetually","hardly ever","invariably","incessantly",
 "habitually","repeatedly","daily"].forEach(function(w){ADV_KIND[w]="F"});
["just","already","soon","still","yet","recently","lately","currently","presently",
 "formerly","previously","initially","originally","ultimately","finally","eventually",
 "afterwards","subsequently","beforehand","meanwhile","simultaneously","immediately",
 "instantly","promptly","shortly","briefly","temporarily","permanently","freshly"].forEach(function(w){ADV_KIND[w]="T"});
["carefully","quickly","slowly","suddenly","gradually","gently","firmly","loudly","quietly",
 "clearly","easily","happily","sadly","angrily","calmly","confidently","nervously","eagerly",
 "reluctantly","willingly","brilliantly","perfectly","thoroughly","properly","correctly",
 "incorrectly","wrongly","rightly","justly","harshly","strictly","loosely","smoothly",
 "swiftly","steadily","sharply","deeply","strongly","powerfully","forcefully","softly",
 "mildly","heavily","lightly","tightly","boldly","bravely","cheerfully","diligently",
 "elegantly","energetically","enthusiastically","gracefully","gratefully","humbly","keenly",
 "kindly","loyally","neatly","passionately","patiently","persistently","politely","proudly",
 "punctually","rapidly","reliably","respectfully","sincerely","skilfully","tactfully",
 "tenderly","readily","emphatically","doubtfully","definitively","crudely","convincingly",
 "competently","brutally","brightly","blindly","aptly","amiably","alternately","acutely",
 "abundantly","systematically","characteristically","painfully","plentifully"].forEach(function(w){ADV_KIND[w]="M"});
["very","extremely","incredibly","remarkably","exceptionally","considerably","significantly",
 "substantially","dramatically","enormously","tremendously","hugely","absolutely","utterly",
 "totally","completely","entirely","fully","quite","rather","fairly","reasonably","slightly",
 "somewhat","really","truly","highly","moderately","noticeably","decidedly"].forEach(function(w){ADV_KIND[w]="D"});
["probably","possibly","apparently","seemingly","presumably","allegedly","supposedly",
 "evidently","obviously","plainly","certainly","definitely","surely","likely","indeed",
 "inevitably","indisputably","conclusively"].forEach(function(w){ADV_KIND[w]="P"});
["financially","politically","socially","culturally","technically","scientifically",
 "historically","traditionally","officially","formally","informally","publicly","privately",
 "personally","professionally","physically","mentally","emotionally","spiritually",
 "legally","economically","environmentally","ethically","statistically","theoretically",
 "practically","essentially","fundamentally","basically","broadly","roughly","approximately",
 "ideally","strategically","logically","geographically","internationally","nationally",
 "globally","domestically"].forEach(function(w){ADV_KIND[w]="V"});
["mainly","mostly","largely","partly","purely","simply","merely","just","particularly",
 "especially","notably","specifically","exclusively","solely","primarily","chiefly",
 "predominantly"].forEach(function(w){ADV_KIND[w]="Z"});
["away","upstairs","downstairs","outdoors","indoors","ahead","backwards","forwards","sideways",
 "abroad","overseas","locally","somewhere","everywhere","nowhere","anywhere","widely",
 "everywhere"].forEach(function(w){ADV_KIND[w]="L"});
["otherwise","instead","nonetheless","nevertheless","furthermore","moreover","however",
 "therefore","consequently","accordingly","hence","thus","anyway","regardless","admittedly",
 "conversely","besides","likewise","similarly","equally"].forEach(function(w){ADV_KIND[w]="C"});
["fortunately","unfortunately","hopefully","luckily","thankfully","wisely","cleverly",
 "sensibly","honestly","seriously","literally","frankly","surprisingly","unexpectedly",
 "genuinely","actually","precisely","exactly","virtually","mysteriously","conveniently",
 "naturally","deliberately","intentionally","accidentally","coincidentally","secretly",
 "openly","indirectly","casually","adequately","sufficiently","appropriately","correspondingly"].forEach(function(w){ADV_KIND[w]="CM"});

