function conjEsVerb(inf){
  var refl = "";
  var base = inf;
  if(/se$/.test(inf) && inf.length>3){ refl = "se "; base = inf.slice(0,-2); }
  if(ES_IRR_GLOBAL[base]) return [refl+ES_IRR_GLOBAL[base][0], refl+ES_IRR_GLOBAL[base][1]];
  var noAcc = base.replace(/[áéíóú]/g, function(c){return {á:"a",é:"e",í:"i",ó:"o",ú:"u"}[c]});
  if(/ar$/.test(noAcc)) return [refl+base.slice(0,-2)+"ó", refl+base.slice(0,-2)+"a"];
  if(/er$/.test(noAcc)) return [refl+base.slice(0,-2)+"ió", refl+base.slice(0,-2)+"e"];
  if(/ir$/.test(noAcc)) return [refl+base.slice(0,-2)+"ió", refl+base.slice(0,-2)+"e"];
  return [inf, inf];
}
function conjEsExpression(expr){
  if(!expr) return {past:"", pres:""};
  var tokens = expr.trim().split(/\s+/);
  var c = conjEsVerb(tokens[0]);
  var tail = tokens.length>1 ? " " + tokens.slice(1).join(" ") : "";
  return {past: c[0]+tail, pres: c[1]+tail};
}

/* Examples generator: returns array of senses; each sense is {sense, examples:[[en,es],...]} */
function genExamples(cat, word){
  var fullTr = (getTrans(cat, word) || "").trim();
  // Only phrasal verbs and verbs have true semantic multi-senses worth showing separately.
  // For adverbs/adjectives, "/" usually means just an alternative translation (e.g. "alto / alta").
  var splitSenses = (cat==="phrasal" || cat==="verb");
  var senses = fullTr
    ? (splitSenses ? fullTr.split("/").map(function(s){return s.trim()}).filter(Boolean) : [fullTr.split("/")[0].trim()])
    : [""];
  var perSense = senses.length > 1 ? 1 : 2;
  var out = [];
  for(var i=0; i<senses.length; i++){
    var pair = _genExamplesForSense(cat, word, senses[i]);
    out.push({
      sense: senses[i] || "",
      examples: perSense === 1 ? [pair[0]] : [pair[0], pair[1]]
    });
  }
  return out;
}

/* Internal: generates [[en,es],[en,es]] for ONE specific sense (tr is a single sense string) */
function _genExamplesForSense(cat, word, tr){
  var trLow = tr ? tr.charAt(0).toLowerCase()+tr.slice(1) : "";
  var trBr = tr || ("["+word+"]");
  var trLowBr = trLow || ("["+word+"]");
  var ex1="", ex2="", t1="", t2="";

  if(cat==="adverb"){
    var k = advKind(word);
    if(k==="F"){ // frequency
      ex1 = "I "+word+" go to the gym before work.";
      ex2 = "She "+word+" forgets her keys at home.";
      t1  = "Yo "+trLowBr+" voy al gimnasio antes del trabajo.";
      t2  = "Ella "+trLowBr+" olvida las llaves en casa.";
    } else if(k==="T"){ // time
      // "already, yet, just" sit between have+participle naturally
      var midT = {already:1,yet:1,just:1};
      // Mid-position with simple verb: still, currently, recently, lately
      var midSimple = {still:1,currently:1,recently:1,lately:1};
      // Initial position: meanwhile, finally, eventually, ultimately, subsequently, previously, initially, originally, formerly
      if(midT[word]){
        ex1 = "We have "+word+" finished the report.";
        ex2 = "She is "+word+" working on the new design.";
        t1  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+" hemos terminado el informe.";
        t2  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+" está trabajando en el nuevo diseño.";
      } else if(midSimple[word]){
        // For "still" and "currently": present simple works ("She still works")
        // For "recently" and "lately": pairs with perfect or "started/moved" past
        if(word==="recently" || word==="lately"){
          ex1 = "She has "+word+" started working at the local library.";
          ex2 = "They have "+word+" moved to a new apartment.";
          t1  = "Ella ha empezado "+trLowBr+" a trabajar en la biblioteca local.";
          t2  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+" se han mudado a un piso nuevo.";
        } else {
          ex1 = "She "+word+" works at the local library.";
          ex2 = "They "+word+" live in a new apartment.";
          t1  = "Ella "+trLowBr+" trabaja en la biblioteca local.";
          t2  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+" viven en un piso nuevo.";
        }
      } else {
        // soon, immediately, instantly, shortly, promptly, briefly, temporarily, permanently → end position
        // meanwhile, finally, eventually, ultimately, etc. → initial/mid
        ex1 = "She will arrive "+word+" to start the meeting.";
        ex2 = word.charAt(0).toUpperCase()+word.slice(1)+", everything seemed to fall into place.";
        t1  = "Ella llegará "+trLowBr+" para empezar la reunión.";
        t2  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+", todo pareció encajar.";
      }
    } else if(k==="M"){ // manner
      ex1 = "He spoke "+word+" so that everyone could understand.";
      ex2 = "She closed the door "+word+" to avoid waking the baby.";
      t1  = "Habló "+trLowBr+" para que todos pudieran entender.";
      t2  = "Cerró la puerta "+trLowBr+" para no despertar al bebé.";
    } else if(k==="D"){ // degree
      ex1 = "The film was "+word+" interesting from start to finish.";
      ex2 = "I am "+word+" tired after such a long day.";
      t1  = "La película fue "+trLowBr+" interesante de principio a fin.";
      t2  = "Estoy "+trLowBr+" cansado después de un día tan largo.";
    } else if(k==="P"){ // probability
      ex1 = "She will "+word+" arrive before noon.";
      ex2 = "They have "+word+" already heard the news.";
      t1  = "Ella "+trLowBr+" llegará antes del mediodía.";
      t2  = trBr+" ya se han enterado de la noticia.";
    } else if(k==="V"){ // viewpoint
      ex1 = word.charAt(0).toUpperCase()+word.slice(1)+", the company is doing very well this year.";
      ex2 = word.charAt(0).toUpperCase()+word.slice(1)+" speaking, the plan makes a lot of sense.";
      t1  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+", la empresa va muy bien este año.";
      t2  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+" hablando, el plan tiene mucho sentido.";
    } else if(k==="Z"){ // focus
      ex1 = "He works "+word+" from home these days.";
      ex2 = "The course is "+word+" designed for beginners.";
      t1  = "Estos días trabaja "+trLowBr+" desde casa.";
      t2  = "El curso está "+trLowBr+" diseñado para principiantes.";
    } else if(k==="L"){ // place
      ex1 = "They moved "+word+" several years ago.";
      ex2 = "I left my umbrella "+word+" again.";
      t1  = "Se mudaron "+trLowBr+" hace varios años.";
      t2  = "Me he dejado el paraguas "+trLowBr+" otra vez.";
    } else if(k==="C"){ // conjunctive
      ex1 = "It was raining heavily. "+word.charAt(0).toUpperCase()+word.slice(1)+", we went for our walk.";
      ex2 = "The team was exhausted. "+word.charAt(0).toUpperCase()+word.slice(1)+", they kept playing.";
      t1  = "Llovía mucho. "+trBr+", salimos a caminar.";
      t2  = "El equipo estaba agotado. "+trBr+", siguieron jugando.";
    } else if(k==="CM"){ // comment
      ex1 = word.charAt(0).toUpperCase()+word.slice(1)+", nobody was hurt in the accident.";
      ex2 = word.charAt(0).toUpperCase()+word.slice(1)+", I don't think we have enough time.";
      t1  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+", nadie resultó herido en el accidente.";
      t2  = trBr.charAt(0).toUpperCase()+trBr.slice(1)+", no creo que tengamos suficiente tiempo.";
    }
  }

  else if(cat==="adjective"){
    var k2 = adjKind(word);
    // a/an article logic for English
    var art = /^[aeiouAEIOU]/.test(word) ? "an" : "a";
    if(k2==="PR"){ // personality - "alguien" is gender-neutral in Spanish
      ex1 = "He has always been "+art+" "+word+" person.";
      ex2 = "Being "+word+" has helped him in many situations.";
      t1  = "Siempre ha sido alguien "+trLowBr+".";
      t2  = "Ser "+trLowBr+" le ha ayudado en muchas situaciones.";
    } else if(k2==="PH"){ // physical
      ex1 = "He is "+art+" "+word+", well-dressed young man.";
      ex2 = "He looked "+word+" in his new suit.";
      t1  = "Es un joven "+trLowBr+" y bien vestido.";
      t2  = "Se veía "+trLowBr+" con su traje nuevo.";
    } else if(k2==="EM"){ // emotional
      ex1 = "He is "+word+" about the upcoming exam.";
      ex2 = "He looked "+word+" when he heard the news.";
      t1  = "Está "+trLowBr+" por el examen que se acerca.";
      t2  = "Parecía "+trLowBr+" cuando se enteró de la noticia.";
    } else if(k2==="AB"){ // ability
      ex1 = "He is "+art+" "+word+" engineer with twenty years of experience.";
      ex2 = "He is "+word+" enough to handle the project alone.";
      t1  = "Es un ingeniero "+trLowBr+" con veinte años de experiencia.";
      t2  = "Es lo suficientemente "+trLowBr+" para llevar el proyecto solo.";
    } else { // TH - things/ideas
      ex1 = "The report was clear, "+word+" and well-structured.";
      ex2 = "We need a more "+word+" approach to solve this problem.";
      t1  = "El informe era claro, "+trLowBr+" y bien estructurado.";
      t2  = "Necesitamos un enfoque más "+trLowBr+" para resolver este problema.";
    }
  }

  else if(cat==="phrasal"){
    // Irregular pasts for phrasal verb heads
    var IRR_PAST = {bring:"brought",call:"called",carry:"carried",come:"came",cut:"cut",
      deal:"dealt",fall:"fell",get:"got",give:"gave",go:"went",hold:"held",keep:"kept",
      let:"let",look:"looked",make:"made",pick:"picked",put:"put",run:"ran",set:"set",
      stand:"stood",take:"took",turn:"turned",work:"worked",blow:"blew",break:"broke",
      brush:"brushed",bump:"bumped",catch:"caught",check:"checked",cheer:"cheered",
      clear:"cleared",cool:"cooled",count:"counted",cover:"covered",crack:"cracked",
      draw:"drew",drop:"dropped",end:"ended",figure:"figured",fill:"filled",find:"found",
      fit:"fit",grow:"grew",hang:"hung",join:"joined",kick:"kicked",lay:"laid",leave:"left",
      miss:"missed",move:"moved",open:"opened",own:"owned",pass:"passed",point:"pointed",
      pull:"pulled",push:"pushed",reach:"reached",rule:"ruled",show:"showed",sign:"signed",
      slip:"slipped",sort:"sorted",speak:"spoke",speed:"sped",stick:"stuck",stir:"stirred",
      sum:"summed",switch:"switched",talk:"talked",think:"thought",throw:"threw",try:"tried",
      wind:"wound",write:"wrote",act:"acted",add:"added",aim:"aimed",answer:"answered",
      ask:"asked",back:"backed",bail:"bailed",bank:"banked",bear:"bore",beat:"beat",
      beef:"beefed",belt:"belted",blend:"blended",block:"blocked",boil:"boiled",
      book:"booked",boot:"booted",bottle:"bottled",bow:"bowed",branch:"branched",
      brave:"braved",breeze:"breezed",buckle:"buckled",budge:"budged",build:"built",
      burn:"burned",burst:"burst",buy:"bought",calm:"calmed",camp:"camped",cancel:"cancelled",
      cap:"capped",cash:"cashed",cast:"cast",cater:"catered",chalk:"chalked",change:"changed",
      chase:"chased",chat:"chatted",cheat:"cheated",chew:"chewed",chicken:"chickened",
      chill:"chilled",chip:"chipped",choke:"choked",clamp:"clamped",close:"closed",
      club:"clubbed",conjure:"conjured",cook:"cooked",cope:"coped",crop:"cropped",
      dawn:"dawned",die:"died",dig:"dug",dip:"dipped",dish:"dished",dive:"dived",do:"did"};
    var parts = word.split(" ");
    var head = parts[0];
    var rest = parts.slice(1).join(" ");
    var headPast = IRR_PAST[head] || VRB_PAST[head] || (head.match(/e$/)? head+"d" : head+"ed");
    var conj = conjEsExpression(trLowBr);
    ex1 = "She "+headPast+(rest?" "+rest:"")+" during the meeting yesterday.";
    ex2 = "We always "+word+" when problems appear at work.";
    t1  = "Ella "+conj.past+" durante la reunión de ayer.";
    t2  = "Siempre "+conj.pres+" cuando aparecen problemas en el trabajo.";
  }

  else if(cat==="connector"){
    ex1 = "The proposal was strong. "+word+", the committee approved it without changes.";
    ex2 = "He had little experience. "+word+", he was offered the position.";
    t1  = "La propuesta era sólida. "+trBr+", el comité la aprobó sin cambios.";
    t2  = "Tenía poca experiencia. "+trBr+", le ofrecieron el puesto.";
  }

  else if(cat==="starter"){
    ex1 = word+", education plays a key role in personal development.";
    ex2 = word+", more research is needed before drawing firm conclusions.";
    t1  = trBr+", la educación juega un papel clave en el desarrollo personal.";
    t2  = trBr+", se necesita más investigación antes de sacar conclusiones firmes.";
  }

  else if(cat==="verb"){
    var tp = VRB_TYPE[word]||"";
    var past = VRB_PAST[word] || (word.match(/e$/)? word+"d" : word+"ed");
    var third = VRB_3SG[word] || (word.match(/[sxz]$|ch$|sh$/)? word+"es" : word+"s");
    var conjV = conjEsExpression(trLowBr);
    if(tp==="transitive"){
      ex1 = "She "+past+" the project ahead of schedule.";
      ex2 = "The team will "+word+" the new strategy next month.";
      t1  = "Ella "+conjV.past+" el proyecto antes de lo previsto.";
      t2  = "El equipo va a "+trLowBr+" la nueva estrategia el mes que viene.";
    } else {
      ex1 = "She "+past+" calmly when the situation got difficult.";
      ex2 = "He often "+third+" in challenging situations.";
      t1  = "Ella "+conjV.past+" con calma cuando la situación se complicó.";
      t2  = "Él a menudo "+conjV.pres+" en situaciones difíciles.";
    }
  }

  return [[ex1, t1], [ex2, t2]];
}

function getTypeName(cat){
  if(cat==="adverb") return "Adverbio";
  if(cat==="adjective") return "Adjetivo";
  if(cat==="phrasal") return "Phrasal Verb";
  if(cat==="connector") return "Conector";
  if(cat==="starter") return "Inicio de Frase";
  if(cat==="verb") return "Verbo";
  return cat;
}

function getRegisterName(r){
  if(r==="F") return "Formal";
  if(r==="I") return "Informal";
  return "Neutro";
}

function getRegisterDesc(r){
  if(r==="F") return "Apropiado para contextos profesionales, académicos o escritos. Se usa en informes, correos formales, ensayos y comunicación oficial.";
  if(r==="I") return "Apropiado para conversación casual con amigos, mensajes informales y contextos relajados. Evítalo en escritos académicos o profesionales.";
  return "Adecuado para la mayoría de contextos, tanto formales como informales. Es seguro usarlo en cualquier situación habitual.";
}

function capFirst(s){
  s = (s || "").trim();
  return s ? s.charAt(0).toUpperCase() + s.slice(1) : s;
}

