function getCorrect(cat,item){return(cat==="adverb"||cat==="adjective"||cat==="starter"||cat==="verb")?item:item[0]}
function getExplain(cat,item,trans){
  var word = getCorrect(cat,item);
  if(cat==="adverb")return '"'+word+'" significa "'+(ADV_TR[word]||"")+'" en español. Es un adverbio. '+(STRUCT[word]||"");
  if(cat==="adjective")return '"'+word+'" significa "'+(ADJ_TR[word]||"")+'" en español. Es un adjetivo. '+(STRUCT[word]||"");
  if(cat==="phrasal")return '"'+word+'" significa "'+(PHR_TR[word]||"")+'" en español. '+(STRUCT[word]||"");
  if(cat==="connector")return '"'+word+'" es un conector que significa "'+(CON_TR[word]||"")+'". '+(STRUCT[word]||"");
  if(cat==="starter")return '"'+word+'" se traduce como "'+(STR_TR[word]||"")+'". '+(STRUCT[word]||"");
  if(cat==="verb"){var tp=VRB_TYPE[word]||"";var tpEs=tp==="transitive"?"transitivo":"intransitivo";return '"'+word+'" es un verbo '+tpEs+'. Significa "'+(VRB_TR[word]||"")+'" en español.'}
}

/* getWrong: picks 3 distractors from same category, EXCLUDING any word that
   shares the same Spanish translation (to guarantee 1 correct answer) */
function getWrong(cat,correct,correctTrans,n){
  var pool;
  var trans;
  if(cat==="adverb"){pool=ADVERBS;trans=ADV_TR}
  else if(cat==="adjective"){pool=ADJECTIVES;trans=ADJ_TR}
  else if(cat==="phrasal"){pool=PHRASALS.map(function(x){return x[0]});trans=PHR_TR}
  else if(cat==="connector"){pool=CONNECTORS.map(function(x){return x[0]});trans=CON_TR}
  else if(cat==="starter"){pool=STARTERS;trans=STR_TR}
  else {pool=VERBS;trans=VRB_TR}
  
  /* Filter: not equal to correct, AND Spanish translation is different */
  var filtered = pool.filter(function(x){
    if(x===correct) return false;
    var t = (trans[x]||"").toLowerCase().trim();
    var ct = (correctTrans||"").toLowerCase().trim();
    if(!t || !ct) return true;
    /* If translations share any significant word, skip */
    var tWords = t.split(/[\s,/]+/).filter(function(w){return w.length>3});
    var ctWords = ct.split(/[\s,/]+/).filter(function(w){return w.length>3});
    for(var i=0;i<tWords.length;i++){
      if(ctWords.indexOf(tWords[i])>=0) return false;
    }
    return true;
  });
  return pick(filtered, n);
}


function buildDefaultQuizQuestion(cat,item){
  var correct=getCorrect(cat,item);
  var ctrans=getTrans(cat,correct);
  var wrongs=getWrong(cat,correct,ctrans,3);
  var opts=[correct].concat(wrongs);
  var qtxt;
  if(cat==="adverb") qtxt='¿Cuál es la traducción al inglés del adverbio "<strong>'+ctrans+'</strong>"?';
  else if(cat==="adjective") qtxt='¿Cuál es la traducción al inglés del adjetivo "<strong>'+ctrans+'</strong>"?';
  else if(cat==="phrasal") qtxt='¿Cuál es el phrasal verb en inglés que significa "<strong>'+ctrans+'</strong>"?';
  else if(cat==="connector") qtxt='¿Cuál es el conector en inglés que equivale a "<strong>'+ctrans+'</strong>"?';
  else if(cat==="starter") qtxt='¿Cuál es la frase de inicio en inglés que equivale a "<strong>'+ctrans+'</strong>"?';
  else qtxt='¿Cuál es el verbo en inglés que significa "<strong>'+ctrans+'</strong>"?';
  return {cat:cat,item:item,sentence:qtxt,correct:correct,trans:ctrans,opts:opts,explain:getExplain(cat,item,ctrans)};
}
function applyQuizEdit(q){
  var originalCorrect = q.correct;
  var k=(q.cat||"")+"||"+(originalCorrect||"");
  var ed=USER_QUIZ_EDITS[k];
  if(!ed) return q;
  if(ed.sentence) q.sentence=ed.sentence;
  if(ed.correct) q.correct=ed.correct;
  if(ed.opts && ed.opts.length>=4){
    q.opts=ed.opts.slice(0,4).filter(Boolean);
    if(q.opts.indexOf(q.correct)<0) q.opts[0]=q.correct;
  }
  return q;
}

/* Generate questions - SPANISH -> ENGLISH format guarantees 1 correct answer */
function genQs(pool){
  if(pool){qs=pool;quizTotalQuestions=qs.length;quizPerPlayerTotal=qs.length;return}
  var active=Object.keys(selCats).filter(function(c){return selCats[c]});
  var total=selQCount*numP;
  quizPerPlayerTotal=selQCount;
  quizTotalQuestions=total;
  var perCat=Math.floor(total/active.length),rem=total-(perCat*active.length);
  qs=[];
  active.forEach(function(cat,idx){
    var n=perCat+(idx<rem?1:0);
    var src;
    if(cat==="adverb")src=ADVERBS;else if(cat==="adjective")src=ADJECTIVES;
    else if(cat==="phrasal")src=PHRASALS;else if(cat==="connector")src=CONNECTORS;
    else if(cat==="starter")src=STARTERS;else src=VERBS;
    var items=pick(src,n);
    items.forEach(function(item){
      var q=applyQuizEdit(buildDefaultQuizQuestion(cat,item));
      if(!USER_QUIZ_EDITS[(q.cat||"")+"||"+(q.correct||"")]) q.opts=shuf(q.opts);
      qs.push(q);
    });
  });
  qs=shuf(qs);
}

var BADGE={adverb:{cls:"b-adverb",lbl:"Adverbio"},adjective:{cls:"b-adjective",lbl:"Adjetivo"},phrasal:{cls:"b-phrasal",lbl:"Phrasal Verb"},connector:{cls:"b-connector",lbl:"Conector"},starter:{cls:"b-starter",lbl:"Inicio de Frase"},verb:{cls:"b-verb",lbl:"Verbo"}};

function renderQ(){
  var q=qs[curQ],total=qs.length;answered=false;
  var playerQuestion=Math.floor(curQ/numP)+1;
  document.getElementById("prog").style.width=((curQ/total)*100)+"%";
  document.getElementById("qcnt").textContent=numP===2?("Pregunta "+playerQuestion+" de "+quizPerPlayerTotal+" para "+players[curP].name):("Pregunta "+(curQ+1)+" de "+quizPerPlayerTotal);
  document.getElementById("turnBanner").innerHTML='<div class="turn-label">Responde ahora</div><div class="turn-name">'+players[curP].name+'</div><div class="turn-count">Pregunta '+(numP===2?playerQuestion:(curQ+1))+' de '+quizPerPlayerTotal+'</div>';
  var b=BADGE[q.cat];var badge=document.getElementById("qbadge");badge.className="qbadge "+b.cls;badge.textContent=b.lbl;
  var ch="";for(var i=0;i<players.length;i++)ch+='<span class="chip p'+(i+1)+(i===curP?" on":"")+'">'+(players[i].name)+'</span>';
  document.getElementById("chips").innerHTML=ch;
  renderScores();
  document.getElementById("qtext").innerHTML=q.sentence+'<br><br><span class="blank" id="blankSlot">arrastra aquí</span>';
  var blank=document.getElementById("blankSlot");
  blank.addEventListener("dragover",function(e){e.preventDefault();blank.classList.add("over")});
  blank.addEventListener("dragleave",function(){blank.classList.remove("over")});
  blank.addEventListener("drop",function(e){e.preventDefault();blank.classList.remove("over");if(!answered&&dragVal)doAnswer(dragVal)});
  var grid=document.getElementById("opts");grid.innerHTML="";
  q.opts.forEach(function(opt){
    var tr=getTrans(q.cat,opt);
    var d=document.createElement("div");d.className="opt";d.setAttribute("draggable","true");d.dataset.val=opt;
    d.innerHTML='<span class="opt-word">'+opt+'</span><span class="opt-trans">'+tr+'</span>';
    d.addEventListener("dragstart",function(e){if(answered){e.preventDefault();return}dragVal=opt;d.classList.add("drag")});
    d.addEventListener("dragend",function(){d.classList.remove("drag")});
    d.addEventListener("touchstart",touchS,{passive:false});d.addEventListener("touchmove",touchM,{passive:false});d.addEventListener("touchend",touchE);
    d.addEventListener("click",function(){if(!answered)doAnswer(opt)});
    grid.appendChild(d);
  });
  var exp=document.getElementById("exp");
  exp.className="expbox";exp.innerHTML="";
  document.getElementById("btnNext").className="btn-next";

  var k = (q.cat||"")+"||"+(q.correct||"");
  var qEd = USER_QUIZ_EDITS[k] || {};
  var qvBtn = document.getElementById("quizVerifyBtn");
  if(qvBtn) qvBtn.classList.toggle("verified", qEd.quizVerified === true);
}

function toggleQuizVerify(e){
  e.stopPropagation();
  var q = qs[curQ];
  if(!q) return;
  var k = (q.cat||"")+"||"+(q.correct||"");
  USER_QUIZ_EDITS[k] = USER_QUIZ_EDITS[k] || {};
  USER_QUIZ_EDITS[k].quizVerified = !USER_QUIZ_EDITS[k].quizVerified;
  saveQuizEdits();
  var qvBtn = document.getElementById("quizVerifyBtn");
  if(qvBtn) qvBtn.classList.toggle("verified", USER_QUIZ_EDITS[k].quizVerified);
}
function renderScores(){
  var html="";
  for(var i=0;i<players.length;i++)html+='<div class="sc p'+(i+1)+'"><div class="sc-name">'+players[i].name+'</div><div class="sc-nums"><span class="n-ok">'+players[i].ok+'</span><span class="n-bad">/'+players[i].bad+'</span><span class="n-tot"> de '+quizPerPlayerTotal+'</span></div></div>';
  document.getElementById("sboard").innerHTML=html;
}
function doAnswer(val){
  if(answered)return;answered=true;
  var q=qs[curQ],isOk=(val===q.correct);
  if(isOk)players[curP].ok++;else{players[curP].bad++;players[curP].wrong.push({cat:q.cat,item:q.item,sentence:q.sentence,correct:q.correct,trans:q.trans,opts:q.opts,explain:q.explain})}
  var blank=document.getElementById("blankSlot");blank.textContent=val;blank.classList.remove("over");blank.classList.add(isOk?"ok":"bad");
  document.querySelectorAll("#opts .opt").forEach(function(o){var v=o.dataset.val;if(v===q.correct)o.classList.add("ok");else if(v===val&&!isOk)o.classList.add("bad");o.classList.add("dis")});
  var exp=document.getElementById("exp");
  exp.innerHTML='<div class="exp-r '+(isOk?"ok":"bad")+'">'+(isOk?"✓ ¡Correcto!":'✗ Incorrecto — la respuesta era: <strong>'+q.correct+'</strong>')+'</div><div>'+q.explain+'</div>';
  exp.className="expbox show "+(isOk?"exp-ok":"exp-bad");
  document.getElementById("btnNext").className="btn-next show";
  renderScores();
}
function nextQ(){if(numP===2)curP=(curP+1)%2;curQ++;if(curQ>=qs.length)showResults();else renderQ()}

function launchConfetti(){
  var colors=["#d4a020","#9b6f3f","#6b4423","#3d7a3d","#c9a87c","#b08020"];
  for(var i=0;i<60;i++){
    (function(){
      var c=document.createElement("div");c.className="confetti";
      c.style.left=(Math.random()*100)+"vw";
      c.style.background=colors[Math.floor(Math.random()*colors.length)];
      c.style.animationDelay=(Math.random()*1.5)+"s";
      c.style.animationDuration=(2.5+Math.random()*2)+"s";
      if(Math.random()>.5) c.style.borderRadius="50%";
      document.body.appendChild(c);
      setTimeout(function(){c.remove()},5000);
    })();
  }
}

function showResults(){
  document.getElementById("prog").style.width="100%";
  var total=quizPerPlayerTotal;
  var allPerfect = players.every(function(p){return p.ok===total});
  var anyPerfect = players.some(function(p){return p.ok===total});
  var trophyArea=document.getElementById("trophyArea");
  var title=document.getElementById("resultsTitle");
  var pmsg=document.getElementById("perfectMsg");
  if(allPerfect){
    trophyArea.innerHTML='<div class="perfect-trophy">🏆</div>';
    title.textContent="¡PERFECTO!";title.style.color="#b08020";
    if(players.length===1){
      pmsg.innerHTML='<div class="perfect-msg"><h3>🌟 ¡Increíble, '+players[0].name+'! 🌟</h3><p>Has acertado <strong>TODAS</strong> las '+total+' preguntas. Dominas el inglés británico como un verdadero experto. ¡Felicidades por este logro perfecto!</p></div>';
    } else {
      pmsg.innerHTML='<div class="perfect-msg"><h3>🌟 ¡EMPATE PERFECTO! 🌟</h3><p>¡Ambos jugadores habéis acertado las '+total+' preguntas! Un duelo de auténticos maestros del inglés británico. ¡Enhorabuena a los dos!</p></div>';
    }
    pmsg.style.display="block";
    launchConfetti();
  } else if(anyPerfect){
    trophyArea.innerHTML='<div class="perfect-trophy">🏆</div>';
    title.textContent="¡PERFECTO!";title.style.color="#b08020";
    var winner=players.find(function(p){return p.ok===total});
    pmsg.innerHTML='<div class="perfect-msg"><h3>🌟 ¡Increíble, '+winner.name+'! 🌟</h3><p>Has acertado <strong>TODAS</strong> las '+total+' preguntas. ¡Felicidades por este logro perfecto!</p></div>';
    pmsg.style.display="block";
    launchConfetti();
  } else {
    trophyArea.innerHTML='<div class="trophy">🏆</div>';
    title.textContent="¡Quiz Completado!";title.style.color="";
    pmsg.style.display="none";pmsg.innerHTML="";
  }
  var html="";
  for(var i=0;i<players.length;i++){
    var p=players[i],pct=total>0?Math.round(p.ok/total*100):0;
    var perfClass = p.ok===total ? " perfect" : "";
    html+='<div class="rcard p'+(i+1)+perfClass+'"><div class="rname">'+p.name+(p.ok===total?' 🏆':'')+'</div><div class="rbig">'+p.ok+'<span>/'+total+'</span></div><div class="rpct">'+pct+'% de acierto</div><div class="rbars"><span class="r-ok">✓ '+p.ok+' correctas</span><span class="r-bad">✗ '+p.bad+' erróneas</span></div></div>';
  }
  document.getElementById("rcards").innerHTML=html;
  document.getElementById("btnRetry").style.display=players.some(function(p){return p.wrong.length>0})?"":"none";
  showScreen("resultsScreen");
}

function retryWrong(){
  var all=[];for(var i=0;i<players.length;i++)for(var j=0;j<players[i].wrong.length;j++)all.push(players[i].wrong[j]);
  if(!all.length)return;
  var pool=all.map(function(q){var w=getWrong(q.cat,q.correct,q.trans,3);return{cat:q.cat,item:q.item,sentence:q.sentence,correct:q.correct,trans:q.trans,opts:shuf([q.correct].concat(w)),explain:q.explain}});
  for(var i=0;i<players.length;i++){players[i].ok=0;players[i].bad=0;players[i].wrong=[]}
  curP=0;curQ=0;genQs(pool);showScreen("quizScreen");renderQ();
}

function touchS(e){if(answered)return;touchEl=e.currentTarget;var t=e.touches[0];touchGhost=document.createElement("div");touchGhost.className="tghost";touchGhost.textContent=touchEl.dataset.val;document.body.appendChild(touchGhost);mvTG(t.clientX,t.clientY);e.preventDefault()}
function touchM(e){if(!touchGhost)return;mvTG(e.touches[0].clientX,e.touches[0].clientY);e.preventDefault()}
function touchE(e){if(!touchGhost)return;var t=e.changedTouches[0];var el=document.elementFromPoint(t.clientX,t.clientY);touchGhost.remove();touchGhost=null;var blank=document.getElementById("blankSlot");if(blank&&(el===blank||blank.contains(el))&&!answered)doAnswer(touchEl.dataset.val);touchEl=null}
function mvTG(x,y){if(!touchGhost)return;touchGhost.style.left=x+"px";touchGhost.style.top=y+"px"}


/* USER EDITS - saved in browser and embedded when exporting */
var USER_EDITS = {};/* USER_EDITS_MARKER */
var USER_CARDS = [];/* USER_CARDS_MARKER */
var USER_QUIZ_EDITS = {};/* USER_QUIZ_EDITS_MARKER */
var EDIT_PASSWORD = "5eli5";
var STUDY_EDIT_MODE = false;
try{
  var savedEdits = localStorage.getItem("english2026_user_edits");
  if(savedEdits){ USER_EDITS = Object.assign({}, USER_EDITS, JSON.parse(savedEdits)); }
  var savedCards = localStorage.getItem("english2026_user_cards");
  if(savedCards){ USER_CARDS = USER_CARDS.concat(JSON.parse(savedCards)); }
  var savedQuizEdits = localStorage.getItem("english2026_quiz_edits");
  if(savedQuizEdits){ USER_QUIZ_EDITS = Object.assign({}, USER_QUIZ_EDITS, JSON.parse(savedQuizEdits)); }
}catch(e){}
function cardKey(c){ return (c.cat||"")+"||"+(c.originalWord || c.word ||""); }
function saveEdits(){ try{ localStorage.setItem("english2026_user_edits", JSON.stringify(USER_EDITS)); }catch(e){} }
function saveUserCards(){ try{ localStorage.setItem("english2026_user_cards", JSON.stringify(USER_CARDS)); }catch(e){} }
function saveQuizEdits(){ try{ localStorage.setItem("english2026_quiz_edits", JSON.stringify(USER_QUIZ_EDITS)); }catch(e){} }
function getStudyCards(){
  var list = ALL_CARDS.concat(USER_CARDS);
  list.forEach(function(c) {
    c.originalWord = c.originalWord || c.word;
    var k = cardKey(c);
    var edit = USER_EDITS[k];
    if (edit && edit.customWord) c.word = edit.customWord;
  });
  return list.filter(function(c) {
    var k = cardKey(c);
    return !(USER_EDITS[k] && USER_EDITS[k].deleted);
  });
}

function deleteCurrentCard() {
  if(!STUDY_EDIT_MODE) return;
  var c = getCurrentCard(); if(!c) return;
  if(!confirm("¿Seguro que quieres borrar esta flashcard?")) return;
  var k = cardKey(c);
  USER_EDITS[k] = USER_EDITS[k] || {};
  USER_EDITS[k].deleted = true;
  saveEdits();
  
  if (USER_CARDS.includes(c)) saveUserCards();
  
  studyList = getStudyCards();
  updateHomeTotal();
  
  if(studyList.length === 0) {
    alert("Ya no hay flashcards.");
    showScreen('home');
    return;
  }
  if(studyIdx >= studyList.length) studyIdx = 0;
  renderStudy();
}

function saveFrontWord(el) {
  if(!STUDY_EDIT_MODE) return;
  var c = getCurrentCard(); if(!c) return;
  var newWord = el.textContent.trim();
  if(!newWord || newWord === c.word) { el.textContent = c.word; return; }
  
  c.word = newWord;
  var k = cardKey(c);
  USER_EDITS[k] = USER_EDITS[k] || {};
  USER_EDITS[k].customWord = newWord;
  saveEdits();
  if (USER_CARDS.includes(c)) saveUserCards();
  
  var backWord = document.getElementById("fcBackWord");
  if (backWord) backWord.textContent = newWord;
}
var EMBED_FLASHCARD_COUNT_CACHE = {};
function decodeEmbeddedHtml(payload){
  var bin = atob(payload), bytes = new Uint8Array(bin.length);
  for(var i=0;i<bin.length;i++) bytes[i] = bin.charCodeAt(i);
  return new TextDecoder("utf-8").decode(bytes);
}
function countEmbeddedFlashcards(payload, fallback, key){
  if(EMBED_FLASHCARD_COUNT_CACHE[key]!=null) return EMBED_FLASHCARD_COUNT_CACHE[key];
  var count=fallback;
  try{
    var txt=decodeEmbeddedHtml(payload);
    var m=txt.match(/(\d+)\s+flashcards/i);
    if(m) count=parseInt(m[1],10);
    else{
      var ids=txt.match(/\{id\s*:/g);
      if(ids&&ids.length) count=ids.length;
    }
  }catch(e){}
  EMBED_FLASHCARD_COUNT_CACHE[key]=count;
  return count;
}
function getTotalFlashcardsCount(){
  return getStudyCards().length;
}
function updateHomeTotal(){
  var el=document.getElementById("totalFlashcards");
  if(el) el.textContent=getTotalFlashcardsCount().toLocaleString("es-ES");
}
function getCurrentCard(){ if(!studyList || !studyList.length) return null; return studyList[studyIdx]; }
function getEdit(c){ return USER_EDITS[cardKey(c)] || {}; }
function setEditableText(id, value, field){
  var el=document.getElementById(id); if(!el) return;
  el.textContent = value || "—";
  el.contentEditable = STUDY_EDIT_MODE ? "true" : "false";
  el.classList.toggle("editable-field", STUDY_EDIT_MODE);
  if(STUDY_EDIT_MODE) el.dataset.editField = field; else delete el.dataset.editField;
}
function saveFieldFromElement(el){
  if(!STUDY_EDIT_MODE) return;
  var c=getCurrentCard(); if(!c || !el || !el.dataset.editField) return;
  var k=cardKey(c), f=el.dataset.editField;
  USER_EDITS[k]=USER_EDITS[k]||{};
  USER_EDITS[k][f]=el.textContent.trim();
  saveEdits();
}
function saveExamplesFromDom(){
  if(!STUDY_EDIT_MODE) return;
  var c=getCurrentCard(); if(!c) return;
  var k=cardKey(c);
  var rows=[];
  document.querySelectorAll('#fcExamplesContainer .fc-sense').forEach(function(senseEl){
    var sense = senseEl.querySelector('.fc-sense-lbl') ? senseEl.querySelector('.fc-sense-lbl').textContent.replace(/^Significado\s*\d+\s*:\s*/i,'').trim() : '';
    var examples=[];
    var exEls=senseEl.querySelectorAll('.fc-ex');
    var trEls=senseEl.querySelectorAll('.fc-ex-tr');
    for(var i=0;i<exEls.length;i++){
      examples.push([exEls[i].textContent.replace(/^\d+\.\s*/, '').trim(), (trEls[i]?trEls[i].textContent.trim():"")]);
    }
    rows.push({sense:sense, examples:examples});
  });
  USER_EDITS[k]=USER_EDITS[k]||{};
  USER_EDITS[k].examples=rows;
  saveEdits();
}
var pendingPasswordAction = null;
function openActionPasswordModal(text, onOk){
  pendingPasswordAction = onOk;
  document.getElementById("actionPasswordText").textContent = text;
  document.getElementById("actionPasswordInput").value = "";
  document.getElementById("actionPasswordError").classList.remove("show");
  var modal=document.getElementById("actionPasswordModal");
  modal.classList.add("show"); modal.setAttribute("aria-hidden","false");
  setTimeout(function(){document.getElementById("actionPasswordInput").focus()},50);
}
function closeActionPasswordModal(){
  var modal=document.getElementById("actionPasswordModal");
  modal.classList.remove("show"); modal.setAttribute("aria-hidden","true");
  pendingPasswordAction = null;
}
function tryActionPassword(){
  if(document.getElementById("actionPasswordInput").value===EDIT_PASSWORD){
    var action=pendingPasswordAction;
    closeActionPasswordModal();
    if(action) action();
  } else {
    document.getElementById("actionPasswordError").classList.add("show");
    document.getElementById("actionPasswordInput").select();
  }
}
