document.getElementById("inpImportData").addEventListener("change", function(e) {
  var file = e.target.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    try {
      var data = JSON.parse(e.target.result);
      if (data.USER_CARDS) USER_CARDS = data.USER_CARDS;
      if (data.USER_EDITS) USER_EDITS = data.USER_EDITS;
      if (data.USER_QUIZ_EDITS) USER_QUIZ_EDITS = data.USER_QUIZ_EDITS;
      saveUserCards();
      saveEdits();
      saveQuizEdits();
      updateHomeCounts();
      alert("¡Datos importados correctamente! Se han cargado las tarjetas.");
    } catch(err) {
      alert("Error al importar el archivo. Comprueba que sea válido.");
    }
  };
  reader.readAsText(file);
});

